firmware_template.source:
#include "ina219_sensor.h"
#include <Wire.h>
#include <Adafruit_INA219.h>
#include "config.h"

static Adafruit_INA219 _ina(0x40);
static bool _inaReady = false;
static float _busV = 0, _currentMa = 0, _powerMw = 0, _shuntMv = 0;

void ina219_setup() {
    Wire.begin(21, 22);
    if (_ina.begin(&Wire)) {
        _inaReady = true;
        _ina.setCalibration_32V_2A();
        Serial.println("[ina219] Power monitor ready");
    } else {
        Serial.println("[ina219] FAILED");
    }
}

void ina219_loop() {
    if (!_inaReady) return;
    _busV = _ina.getBusVoltage_V();
    _shuntMv = _ina.getShuntVoltage_mV();
    _currentMa = _ina.getCurrent_mA();
    _powerMw = _ina.getPower_mW();
}

float ina219_bus_voltage() { return _busV; }
float ina219_current_ma() { return _currentMa; }
float ina219_power_mw() { return _powerMw; }
float ina219_shunt_voltage() { return _shuntMv; }
bool ina219_ready() { return _inaReady; }
